    if (k < 0 || k > n) return 0;
    return (((fact[n] * invFact[k]) % 1000000007) * invFact[n - k]) % 1000000007;
}

// Helper function to precompute factorials and inverse factorials up to max_val
void precompute_factorials(int max_val, vector<long long>& fact, vector<long long>& invFact) {
    long long MOD = 1000000007;
    fact.resize(max_val + 1);
    invFact.resize(max_val + 1);

    fact[0] = 1;
    for (int i = 1; i <= max_val; ++i) {
        fact[i] = (fact[i - 1] * i) % MOD;
    }

    invFact[max_val] = inverse(fact[max_val]);
    for (int i = max_val - 1; i >= 0; --i) {
        invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
    }
