    // Number of people to the right of pos (indices pos + 1 to n - 1)
    int right_count = n - 1 - pos;

    // The total number of people visible is the sum of visible people from the left and visible people from the right.
    // Let k_L be the number of people seen from the left side (i < pos).
    // Let k_R be the number of people seen from the right side (i > pos).
    // We need k_L + k_R = k.

    // For i < pos: Person i is visible to pos if i chooses 'L'.
    // Number of ways to choose k_L people from 'left_count' to choose 'L' is C(left_count, k_L).

    // For i > pos: Person i is visible to pos if i chooses 'R'.
