            long long ways_right = combinations(right_count, k_R, fact, invFact);

            // Total ways for this specific (k_L, k_R) split
            long long ways_split = (ways_left * ways_right) % MOD;

            total_ways = (total_ways + ways_split) % MOD;
        }
    }

    // Finally, multiply by the 2 choices for person 'pos' (L or R), as this does not affect the count k.
    long long result = (total_ways * 2) % MOD;

