        base = (base * base) % MOD;
        exp /= 2;
    }
    return res;
}

// 组合数 C(n, k) % MOD
// 由于 n 最大是 10^5，我们可以预处理阶乘和逆元，但在这个特定问题中，我们只需要组合数，
// 并且我们可以用动态规划或者直接计算。由于 n 较小，预处理是可行的，但这里直接使用迭代计算组合数更简单，
// 只要确保我们能计算出 C(n, k) 即可。
// 在此问题中，我们需要的组合数是 C(left_count, k_left) * C(right_count, k_right)，
// 且 k_left + k_right = k。
// 我们可以预处理阶乘和逆元。

long long fact[100005];
long long invFact[100005];

// 快速幂求逆元 (a^-1 % m)
long long modInverse(long long n) {
    return power(n, MOD - 2);
}

// 预处理阶乘和逆阶乘
void precompute_factorials(int max_n) {
    fact[0] = 1;
    for (int i = 1; i <= max_n; i++) {
        fact[i] = (fact[i - 1] * i) % MOD;
    }
    invFact[max_n] = modInverse(fact[max_n]);
    for (int i = max_n - 1; i >= 0; i--) {
        invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
    }
}

// 组合数 C(n, k) % MOD
long long nCr_mod(int n, int r) {
    if (r < 0 || r > n) return 0;
    if (r == 0 || r == n) return 1;
    if (r > n / 2) r = n - r;
    // C(n, r) = n! / (r! * (n-r)!)
    long long num = fact[n];
    long long den = (invFact[r] * invFact[n - r]) % MOD;
    return (num * den) % MOD;
