    // k_right 必须在 [0, right_count] 之间。

    for (int k_left = 0; k_left <= K; k_left++) {
        int k_right = K - k_left;

        // 检查 k_right 是否在有效范围内
        if (k_right < 0 || k_right > right_count) {
            continue;
        }

        // 左侧的贡献:
        // 左侧的人 i < pos 看到 pos 的人当且仅当 i 选择 'L'。
        // 我们需要恰好有 k_left 个人选择 'L' (在 left_count 个人中选择 k_left 个)。
