        // 剩余 right_count - k_right 个人选择 'L'。
        // 方式数: C(right_count, k_right)
        long long ways_right = nCr_mod(right_count, k_right);

        // 组合方式数 (左侧和右侧的独立选择乘积)
        long long current_ways = (ways_left * ways_right) % MOD;

        // 累加到总和
        total_ways = (total_ways + current_ways) % MOD;
    }

    // 乘以 pos 人的选择方式 (2 种)
    long long final_answer = (total_ways * 2) % MOD;

    return final_answer;
}
